import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"93. Ten Hour Break Between Overtime Recall","description":"","frontmatter":{"title":"93. Ten Hour Break Between Overtime Recall","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","shift-work","breaks"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/93-ten-hour-break-between-overtime-recall.md","filePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/93-ten-hour-break-between-overtime-recall.md"}'),n={name:"ebas/mental-health/rpn-pen-mho/hours-of-work/93-ten-hour-break-between-overtime-recall.md"};function l(s,e,i,h,p,c){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_93-ten-hour-break-between-overtime-recall" tabindex="-1">93. Ten Hour Break Between Overtime Recall <a class="header-anchor" href="#_93-ten-hour-break-between-overtime-recall" aria-label="Permalink to &quot;93. Ten Hour Break Between Overtime Recall&quot;">​</a></h1><p>This clause does not apply to recall work performed under sub-<a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/91-oncall-recall-non-catt.html">clause 91.3</a> (Recall Without Return to Workplace).</p><p><strong>93.1</strong> Entitlement When overtime worked (adjacent to a rostered shift (whether immediately before or after) an Employee is entitled to at least 10 consecutive hours off duty between finishing the period of duty and the commencement of the next period of duty.</p><p><strong>93.2</strong> Exception</p><p><strong>(a)</strong> An Employee who works so much overtime that the Employee would not have had at least 10 hours continuously off in accordance with clause 93.1 will be released after completion of the period of duty until the Employees has had 10 consecutive hours off duty. Such a release will be without loss of pay for rostered ordinary hours occurring during such an absence.</p><p><strong>(b)</strong> If an Employee is required by the Employer to attend for, or to continue to work, without having had 10 consecutive hours off duty, the Employee will be paid at the rate of double time until released from duty for 10 consecutive hours off duty, without loss of pay for the rostered hours occurring during such absence.</p><p>93A.Four Clear Days Allowance</p><p><strong>93A.1</strong> Four Clear Days Allowance Note: for other provisions relating to rosters see <a href="/eba/ebas/mental-health/rpn-pen-mho/leave/98-public-holidays.html">clause 98</a> (Rosters).</p><p><strong>(a)</strong> Subject to clause 93A.2(b) below, commencing from the first 28-day roster posted after the date this Agreement commences operation, an Employee is entitled to four clear days in each fortnight of each 28-day roster period free from duty, including on-call/recall work.</p><p><strong>(b)</strong> An Employee who does not receive four clear days off duty as described in clause 93A.2(a) in a four-week roster period will be paid an allowance of 3.167 hours&#39; ordinary pay (pro rata for part-time Employees) on each applicable occasion.</p><p><strong>93A.2</strong> Alternative</p><p><strong>(a)</strong> An Employer or Union covered by this Agreement may propose alternative arrangements to clause 93A.1 to apply to a ward or unit. The proposal may be implemented where the Employer, the Unions and the majority of affected Employees genuinely agree.</p><p><strong>(b)</strong> Any proposal under subclause 93A.2(a) will be provided in writing to the affected Employees and Unions.</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',14)])])}const m=o(n,[["render",l]]);export{d as __pageData,m as default};
